Функция ПолучитьПоследнийДействующийДоговор(Контрагент, ДатаСреза)

	Запрос = Новый Запрос;
	Запрос.Текст = 
		"ВЫБРАТЬ ПЕРВЫЕ 1
		|	Договоры.Ссылка КАК Ссылка
		|ИЗ
		|	Справочник.Договоры КАК Договоры
		|ГДЕ
		|	Договоры.Владелец = &Контрагент
		|	И Договоры.ДатаНачала <= &ДатаСреза
		|	И (Договоры.ДатаОкончания >= &ДатаСреза ИЛИ Договоры.ДатаОкончания ЕСТЬ NULL)
		|УПОРЯДОЧИТЬ ПО
		|	Договоры.ДатаНачала УБЫВАНИЕ";

	Запрос.УстановитьПараметр("Контрагент", Контрагент);
	Запрос.УстановитьПараметр("ДатаСреза", ДатаСреза);

	Результат = Запрос.Выполнить().Выгрузить();

	Если Результат.Количество() = 0 Тогда
		Возврат Неопределено;
	Иначе
		Возврат Результат[0].Ссылка;
	КонецЕсли;

КонецФункции
